use std::collections::{HashMap, Arc};

struct MyCache<K, V> {
    cache: HashMap<K, V>,
}

impl<K: Clone, V: Clone> MyCache<K, V> {
    fn new() -> Self {
        MyCache { cache: HashMap::new() }
    }

    fn get(&self, key: K) -> Result<Option<V>, String> {
        // This is where the magic happens
        if let Some(val) = self.cache.get(key)
            && (val.is_none() || val.unwrap().is_empty())
        {
            return Ok(None);
        }

        self.cache.insert(key, None);
        Ok(Some(val))
    }
}
```

